<?php
namespace Tests\Feature;
use App\Domain\Inventory\InventoryService;use App\Domain\Wallet\GoldReasonCode;use App\Domain\Wallet\WalletService;use App\Models\Character;use App\Models\Item;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class CharacterIsolationTest extends TestCase{use RefreshDatabase;public function test_wallet_inventory_experience_and_health_remain_per_character(){$user=User::factory()->create();$a=Character::factory()->for($user)->create(['experience'=>100,'current_health'=>50]);$b=Character::factory()->for($user)->create(['experience'=>0,'current_health'=>100]);app(WalletService::class)->credit($a,25,GoldReasonCode::ADMIN_GRANT);$item=Item::create(['code'=>'isolated_material','name'=>'Material','item_type'=>'material','rarity'=>'common','is_stackable'=>true,'max_stack'=>20,'status'=>'active']);app(InventoryService::class)->addItem($a,$item,4);$this->assertSame(25,app(WalletService::class)->balance($a)->balance());$this->assertSame(0,app(WalletService::class)->balance($b)->balance());$this->assertTrue(app(InventoryService::class)->hasItem($a,$item,4));$this->assertFalse(app(InventoryService::class)->hasItem($b,$item,1));$this->assertSame(0,$b->fresh()->experience);$this->assertSame(100,$b->fresh()->current_health);}}
